import React, { useState } from 'react';
import { fetchFigmaComponents } from '../figmaapi.js';

const FigmaButton = () => {
    const [buttonData, setButtonData] = useState(null);

    const handleFetch = async () => {
        try {
            const data = await fetchFigmaComponents();
            setButtonData(data); // Store the fetched data in component state
        } catch (error) {
            console.error('Error fetching data:', error);
        }
    };

    return (
        <div>
            <button onClick={handleFetch}>Fetch Figma Button</button>
            {buttonData && <p>Button Data: {JSON.stringify(buttonData)}</p>}
        </div>
    );
};

export default FigmaButton;
